const base = (env.get("PHAB_API_BASE") || "http://localhost:3000/api").replace(/\/+$/, "");
const token = env.get("TELEGRAM_INTEGRATION_TOKEN") || "";

msg.method = "GET";
msg.url = `${base}/integrations/telegram/outbox/pull?limit=20&leaseSec=30`;
msg.headers = {};
if (token) {
  msg.headers["x-integration-token"] = token;
}

return msg;

const commands = Array.isArray(msg.payload?.commands) ? msg.payload.commands : [];
if (!commands.length) {
  return null;
}
msg.payload = commands;
return msg;

const cmd = msg.payload || {};
msg.command = cmd;
msg.commandId = cmd.id;

if (!msg.commandId) {
  msg.failReason = "Missing outbox command id";
  return msg;
}

const method = String(cmd.method || "");
if (method !== "sendMessage" && method !== "answerCallbackQuery") {
  msg.failReason =     `Unsupported method: ${method || "empty"}`;
  return msg;
}

const botToken = env.get("TELEGRAM_BOT_TOKEN") || "";
if (!botToken) {
  msg.failReason = "TELEGRAM_BOT_TOKEN is empty";
  return msg;
}

msg.method = "POST";
msg.url = `https://api.telegram.org/bot${botToken}/${method}`;
msg.headers = { "Content-Type": "application/json" };
msg.payload = cmd.payload || {};
msg.telegramMethod = method;

return msg;

const status = Number(msg.statusCode || 0);
const body = msg.payload;
const okHttp = status >= 200 && status < 300;
const okApi = !(body && typeof body === "object" && body.ok === false);

if (okHttp && okApi) {
  if (body && typeof body === "object" && body.result && body.result.message_id !== undefined) {
    msg.providerMessageId = String(body.result.message_id);
  }
  return [msg, null];
}

let reason = `Telegram send failed (HTTP ${status || "n/a"})`;
if (body && typeof body === "object" && body.description) {
  reason = String(body.description);
}
msg.failReason = reason;
return [null, msg];

if (!msg.commandId) {
  return null;
}

const base = (env.get("PHAB_API_BASE") || "http://localhost:3000/api").replace(/\/+$/, "");
const token = env.get("TELEGRAM_INTEGRATION_TOKEN") || "";

msg.method = "POST";
msg.url = `${base}/integrations/telegram/outbox/${encodeURIComponent(msg.commandId)}/ack`;
msg.headers = { "Content-Type": "application/json" };
if (token) {
  msg.headers["x-integration-token"] = token;
}
msg.payload = msg.providerMessageId ? { providerMessageId: msg.providerMessageId } : {};
msg.outcome = "acked";

return msg;

const commandId = msg.commandId || msg.command?.id;
if (!commandId) {
  return null;
}

const base = (env.get("PHAB_API_BASE") || "http://localhost:3000/api").replace(/\/+$/, "");
const token = env.get("TELEGRAM_INTEGRATION_TOKEN") || "";

let reason = msg.failReason;
if (!reason && msg.error) {
  reason = msg.error.message || String(msg.error);
}
if (!reason) {
  reason = "Telegram send failed";
}

msg.method = "POST";
msg.url = `${base}/integrations/telegram/outbox/${encodeURIComponent(commandId)}/fail`;
msg.headers = { "Content-Type": "application/json" };
if (token) {
  msg.headers["x-integration-token"] = token;
}
msg.payload = { error: String(reason), requeue: true };
msg.outcome = "failed_requeued";

return msg;

msg.payload = {
  statusCode: msg.statusCode || null,
  outcome: msg.outcome || null,
  commandId: msg.commandId || (msg.command && msg.command.id) || null,
  apiResponse: msg.payload
};
return msg;
